from txn_simulator import Workload
from workloads import WORKLOAD_1, WORKLOAD_2, WORKLOAD_3
import time
import random
from collections import defaultdict

def get_best_schedule(workload: Workload, num_seqs: int) -> tuple[int, list[int]]:
    n = workload.num_txns
    if n == 0:
        return 0, []
    if n == 1:
        return workload.get_opt_seq_cost([0]), [0]

    reads = [set() for _ in range(n)]
    writes = [set() for _ in range(n)]
    lengths = [0] * n

    for i in range(n):
        ops = workload.txns[i]
        lengths[i] = len(ops)
        for op_type, key, _, _ in ops:
            if op_type == 'r':
                reads[i].add(key)
            else:
                writes[i].add(key)

    conflict_counts = [0] * n
    for i in range(n):
        for j in range(n):
            if i == j:
                continue
            if writes[i] & writes[j]:
                conflict_counts[i] += 2
            if reads[i] & writes[j]:
                conflict_counts[i] += 1
            if writes[i] & reads[j]:
                conflict_counts[i] += 1

    best_seq = sorted(range(n), key=lambda i: conflict_counts[i], reverse=True)
    best_cost = workload.get_opt_seq_cost(best_seq)

    for _ in range(num_seqs - 1):
        seq = list(range(n))
        random.shuffle(seq)

        for i in range(1, n):
            best_pos = i
            best_local_cost = workload.get_opt_seq_cost(seq[:i+1])

            for pos in range(i):
                candidate = seq[:i+1]
                val = candidate.pop()
                candidate.insert(pos, val)
                cand_cost = workload.get_opt_seq_cost(candidate)
                if cand_cost < best_local_cost:
                    best_local_cost = cand_cost
                    best_pos = pos

            if best_pos != i:
                txn = seq.pop(i)
                seq.insert(best_pos, txn)

        cost = workload.get_opt_seq_cost(seq)
        if cost < best_cost:
            best_cost = cost
            best_seq = seq

    improved = True
    while improved:
        improved = False
        for i in range(n):
            for j in range(i+1, n):
                candidate = best_seq.copy()
                candidate[i], candidate[j] = candidate[j], candidate[i]
                cand_cost = workload.get_opt_seq_cost(candidate)
                if cand_cost < best_cost:
                    best_cost = cand_cost
                    best_seq = candidate
                    improved = True
                    break
            if improved:
                break

    return best_cost, best_seq

def get_random_costs() -> tuple[int, list[list[int]], list[int], float]:
    random.seed(42)
    start_time = time.time()

    workloads = [Workload(WORKLOAD_1), Workload(WORKLOAD_2), Workload(WORKLOAD_3)]
    schedules = []
    costs = []

    for wl in workloads:
        cost, sched = get_best_schedule(wl, 30)
        costs.append(cost)
        schedules.append(sched)

    total_makespan = sum(costs)
    elapsed_time = time.time() - start_time

    return total_makespan, schedules, costs, elapsed_time
